const items = $input.all();

for (const item of items) {
  try {
    // AIの出力をJSONとして解析する
    const aiOutput = JSON.parse(item.json.text);

    // 元のデータに、解析したデータを追加する
    item.json.parsedData = aiOutput;

  } catch (error) {
    // 解析に失敗した場合のエラー処理
    item.json.error = 'Failed to parse JSON';
    item.json.parsedData = {}; // 空のオブジェクトを設定
  }

  // ★★★ ここからが追加・修正部分 ★★★
  let keyword = item.json.parsedData.keyword || ''; // keywordを取得し、無ければ空文字

  // キーワードの前後の空白・改行を削除
  keyword = keyword.trim().replace(/\n/g, '');

  // キーワードが空だった場合、代替キーワードを設定する
  if (keyword === '') {
    keyword = 'ふるさと納税'; // ここで強制的にデフォルト値を設定
  }

  // 処理後のキーワードを元のデータに反映
  item.json.parsedData.keyword = keyword;
  // ★★★ 追加・修正部分ここまで ★★★
}

return items;
